function numeroALetras(num) {
  const unidades = ['', 'un', 'dos', 'tres', 'cuatro', 'cinco', 'seis', 'siete', 'ocho', 'nueve'];
  const decenas = ['', 'diez', 'veinte', 'treinta', 'cuarenta', 'cincuenta', 'sesenta', 'setenta', 'ochenta', 'noventa'];
  const especiales = {
    11: 'once', 12: 'doce', 13: 'trece', 14: 'catorce', 15: 'quince',
    16: 'diecis??is', 17: 'diecisiete', 18: 'dieciocho', 19: 'diecinueve',
    21: 'veintiuno', 22: 'veintid??s', 23: 'veintitr??s', 24: 'veinticuatro',
    25: 'veinticinco', 26: 'veintis??is', 27: 'veintisi??ster', 28: 'veintiocho', 29: 'veintinueve'
  };
  const centenas = ['', 'ciento', 'doscientos', 'trescientos', 'cuatrocientos', 'quinientos', 'seiscientos', 'setecientos', 'ochocientos', 'novecientos'];

  function traducirSeccion(n) {
    if (n === 0) return '';
    if (n === 100) return 'cien';

    let res = '';
    const c = Math.floor(n / 100);
    const d = Math.floor((n % 100) / 10);
    const u = n % 10;
    const du = n % 100;

    if (c > 0) {
      res += centenas[c] + ' ';
    }

    if (du > 0) {
      if (du < 10) {
        res += unidades[du];
      } else if (especiales[du]) {
        res += especiales[du];
      } else {
        res += decenas[d];
        if (u > 0) {
          res += ' y ' + unidades[u];
        }
      }
    }
    return res.trim();
  }

  if (num === 0) return 'cero pesos m/cte';

  let entero = Math.floor(num);
  let letras = '';

  const millones = Math.floor(entero / 1000000);
  const miles = Math.floor((entero % 1000000) / 1000);
  const unidadesResto = entero % 1000;

  if (millones > 0) {
    if (millones === 1) {
      letras += 'un mill??n ';
    } else {
      letras += traducirSeccion(millones) + ' millones ';
    }
  }

  if (miles > 0) {
    if (miles === 1) {
      letras += 'mil ';
    } else {
      letras += traducirSeccion(miles) + ' mil ';
    }
  }

  if (unidadesResto > 0) {
    letras += traducirSeccion(unidadesResto) + ' ';
  }

  return (letras.trim() + ' pesos m/cte').toUpperCase();
}

